test_code:
#include <parlay/thread_specific.h>
#include <parlay/primitives.h>
#include <parlay/slice.h>
#include <iostream>
#include <thread>
#include <chrono>
#include <cassert>
#include <iterator>
#include <vector>
#include <set>
#include <algorithm>

int main() {
 // begin of LLM generated code

parlay::ThreadSpecific<int> default_check_list([]() { return -99; });

// Run parallel_for with a small number of tasks.
// Each thread that gets assigned a task will set its value.
// Threads that don't get assigned a task will retain the default.
parlay::parallel_for(0, 10, [&](size_t) {
  *default_check_list = static_cast<int>(parlay::my_thread_id());
}, 1);

std::vector<int> observed_values;
for (int x : default_check_list) {
  observed_values.push_back(x);
}

 // end of LLM generated code

 assert(observed_values.size() == parlay::num_thread_ids());
 std::set<int> unique_observed_values(observed_values.begin(), observed_values.end());

 // Check that all active thread IDs (up to the number of tasks) are present
 for (size_t i = 0; i < parlay::num_thread_ids(); ++i) {
   if (unique_observed_values.count(static_cast<int>(i))) {
     // This thread ID was active and set its value
   } else {
     // This thread ID was not active or did not set its value, should be -99
     assert(unique_observed_values.count(-99));
   }
 }

 // Check that the default value is present if not all threads were active
 if (parlay::num_thread_ids() > 0) { // If there's at least one thread
   bool all_threads_set_value = true;
   for (size_t i = 0; i < parlay::num_thread_ids(); ++i) {
     if (!unique_observed_values.count(static_cast<int>(i))) {
       all_threads_set_value = false;
       break;
     }
   }
   if (!all_threads_set_value) {
     assert(unique_observed_values.count(-99));
   }
 }

 std::cout << "Test passed!" << std::endl;
 return 0;
}

