// Define the structure needed for the test
struct Node {
  unsigned int value;
  void* data_ptr;
  bool operator==(const Node& other) const {
    return value == other.value && data_ptr == other.data_ptr;
  }
  bool operator<(const Node& other) const {
      return value < other.value; // Comparison based on 'value'
  }
};

int main() {
 // begin of LLM generated code
auto s = parlay::tabulate(95000, [](unsigned int i) -> Node {
  Node elem;
  elem.value = (i * 3 + 1) % 1024; // Keys are small integers [0, 1023]
  elem.data_ptr = nullptr; // Additional data
  return elem;
});

// Sort the sequence using parlay::integer_sort based on the 'value' member
// The key function extracts the integer key
auto sorted = parlay::integer_sort(s, [](const auto& val) -> unsigned long long {
  return val.value;
});

// Stable sort the original sequence in place for comparison
// This relies on Node::operator<
std::stable_sort(std::begin(s), std::end(s));
 // end of LLM generated code

 // Add test assertions here, using `assert()` and not `ASSERT_EQ`
 assert(s.size() == sorted.size()); // Check size

 // Create a copy of the original sequence and sort it using std::sort
 // This allows comparison of the content, regardless of stability
 parlay::sequence<decltype(s)::value_type> s_copy = s;
 std::sort(std::begin(s_copy), std::end(s_copy));

 // Check if the sequence sorted by parlay::integer_sort is identical
 // to the sequence sorted by std::sort (which is also unstable)
 assert(s_copy == sorted);

 // Additionally, verify that the result is indeed sorted according to the key
 // (using the struct's operator< which compares the key member)
 assert(std::is_sorted(std::begin(sorted), std::end(sorted)));

 std::cout << "Test passed!" << std::endl;
