#include <algorithm>
#include <cassert>
#include <string>

struct UncopyableRecord {
    int id;
    std::string name;
    double score;

    UncopyableRecord(int id_val, std::string name_val, double score_val) : id(id_val), name(std::move(name_val)), score(score_val) {}
    UncopyableRecord(const UncopyableRecord&) = delete;
    UncopyableRecord& operator=(const UncopyableRecord&) = delete;
    UncopyableRecord(UncopyableRecord&&) = default;
    UncopyableRecord& operator=(UncopyableRecord&&) = default;

    bool operator==(const UncopyableRecord& other) const {
        return id == other.id && name == other.name && score == other.score;
    }
    bool operator<(const UncopyableRecord& other) const {
        return id < other.id;
    }
};

int main() {
 // begin of LLM generated code
auto s = parlay::tabulate(100000, [](unsigned int i) -> UncopyableRecord {
    return UncopyableRecord(static_cast<int>(100000 - i), "Item_" + std::to_string(i), static_cast<double>(i) / 100.0);
