int main() {
 // begin of LLM generated code
parlay::ThreadSpecific<bool> even_thread_flags;

parlay::parallel_for(0, 1000, [&](size_t) {
  *even_thread_flags = (parlay::my_thread_id() % 2 == 0);
  std::this_thread::sleep_for (std::chrono::milliseconds (10));
}, 1);
 // end of LLM generated code

 // Add test assertions here, using `assert()` and not `ASSERT_EQ`
 assert(parlay::size(even_thread_flags) <= parlay::num_thread_ids());

 // Count how many true/false flags there are
 size_t true_count = 0;
 size_t false_count = 0;
 parlay::for_each(even_thread_flags, [&](bool flag) {
   if (flag) {
     true_count++;
   } else {
     false_count++;
   }
 });

 // At least one thread should have written, and the total count should match size()
 assert(true_count + false_count == parlay::size(even_thread_flags));
 assert(true_count >= 0); // Can be 0 if all threads have odd IDs (unlikely for many threads)
 assert(false_count >= 0); // Can be 0 if all threads have even IDs (unlikely for many threads)

 std::cout << "Test passed!" << std::endl;
 return 0;
}

