#include <iostream>
#include <vector>
#include <parlay/primitives.h>
#include <parlay/slice.h>
#include <algorithm>
#include <functional>
#include <cassert>
#include <parlay/sequence.h>

// Definition needed for the test
struct Point {
    double x, y;

    // For std::stable_sort and std::is_sorted
    bool operator<(const Point& other) const {
        double sum_a = x + y;
        double sum_b = other.x + other.y;
        if (sum_a != sum_b) return sum_a < sum_b;
        if (x != other.x) return x < other.x; // Tie-breaker 1
        return y < other.y; // Tie-breaker 2
    }

    // For vector/sequence operator== which uses element operator==
    bool operator==(const Point& other) const {
        return x == other.x && y == other.y;
    }
};

int main() {
 // begin of LLM generated code

 auto s = parlay::tabulate(30000, [](int i) -> Point {
   Point p;
   p.x = i * 0.5;
   p.y = (i % 100) * 0.1;
   return p;
 });
 auto sorted = parlay::internal::sample_sort(parlay::make_slice(s), [](const Point& a, const Point& b){ return (a.x + a.y) < (b.x + b.y); }, true);

 // end of LLM generated code

  // Custom comparator for std::stable_sort
  auto compare_points_stable = [](const Point& a, const Point& b) {
      double sum_a = a.x + a.y;
      double sum_b = b.x + b.y;
      if (sum_a != sum_b) return sum_a < sum_b;
      if (a.x != b.x) return a.x < b.x; // Secondary key for stability
      return a.y < b.y; // Tertiary key for stability
  };
  std::stable_sort(s.begin(), s.end(), compare_points_stable);

  assert(s.size() == sorted.size());
  assert(s == sorted);
  assert(std::is_sorted(sorted.begin(), sorted.end(), [](const Point& a, const Point& b){ return (a.x + a.y) < (b.x + b.y); }));

 std::cout << "Test passed!" << std::endl;
 return 0;
}

