  std::partial_sum(std::begin(initial_s_for_sequential), std::end(initial_s_for_sequential), std::begin(sequential_psums), TakeMin<double>());

  // Compute sequential total min
  auto sequential_total = std::accumulate(std::begin(initial_s_for_sequential), std::end(initial_s_for_sequential), std::numeric_limits<double>::max(), TakeMin<double>());

