#include <random>

// Minimal definition for UncopyableThing
struct UncopyableThing {
    int value;
    UncopyableThing(int v) : value(v) {}
    UncopyableThing(const UncopyableThing&) = delete; // Disable copy constructor
    UncopyableThing& operator=(const UncopyableThing&) = delete; // Disable copy assignment
    UncopyableThing(UncopyableThing&&) = default; // Enable move constructor
    UncopyableThing& operator=(UncopyableThing&&) = default; // Enable move assignment

    // Comparison for sorting
    bool operator<(const UncopyableThing& other) const { return value < other.value; }
    bool operator>(const UncopyableThing& other) const { return value > other.value; }

    // Equality for assertion (optional, but helpful for sequence comparison)
    bool operator==(const UncopyableThing& other) const { return value == other.value; }
    bool operator!=(const UncopyableThing& other) const { return !(*this == other); }
};

int main() {
// begin of LLM generated code
auto s = parlay::tabulate(100000, [](int i) -> UncopyableThing {
    return UncopyableThing(i);
  });

  // parlay::internal::merge_sort_inplace requires a mutable slice
  parlay::internal::merge_sort_inplace(make_slice(s), [](const UncopyableThing& a, const UncopyableThing& b){
    return a.value > b.value;
  });
// end of LLM generated code

// Add test assertions here, using `assert()` and not `ASSERT_EQ`
auto compare_desc = [](const UncopyableThing& a, const UncopyableThing& b){ return a.value > b.value; };

// To verify the sort, we'll create another sequence and sort it stably
// using std::stable_sort, then compare.
auto s2 = parlay::tabulate(100000, [](int i) -> UncopyableThing {
    return UncopyableThing(i);
  });
std::stable_sort(std::begin(s2), std::end(s2), compare_desc);

// Check if the Parlay sorted sequence is sorted
assert(std::is_sorted(std::begin(s), std::end(s), compare_desc));

// Check if the Parlay sorted sequence is equal to the std::stable_sort result
assert(s.size() == s2.size());
for (size_t i = 0; i < s.size(); ++i) {
    assert(s[i] == s2[i]);
}

std::cout << "Test passed!" << std::endl;

return 0;
}

