#include <parlay/internal/sample_sort.h>
#include <iostream>
#include <parlay/primitives.h>
#include <parlay/sequence.h>
#include <algorithm>
#include <vector>
#include <cassert>
#include <functional>

// Minimal definition of an uncopyable type for testing
struct UncopyableThing {
    int value;

    UncopyableThing(int v) : value(v) {}

    // Disable copy
    UncopyableThing(const UncopyableThing&) = delete;
    UncopyableThing& operator=(const UncopyableThing&) = delete;

    // Allow move
    UncopyableThing(UncopyableThing&&) = default;
    UncopyableThing& operator=(UncopyableThing&&) = default;

    // Comparison operators for sorting and equality check
    bool operator<(const UncopyableThing& other) const {
        return value < other.value;
    }

    bool operator==(const UncopyableThing& other) const {
        return value == other.value;
    }
     bool operator!=(const UncopyableThing& other) const {
        return value != other.value;
    }
};


int main() {
// begin of LLM generated code
auto s = parlay::tabulate(1000, [](int i) -> UncopyableThing {
    return UncopyableThing(i);
  });
  auto s2 = parlay::tabulate(1000, [](int i) -> UncopyableThing {
    return UncopyableThing(i);
  });
  parlay::internal::sample_sort_inplace(parlay::make_slice(s), std::less<UncopyableThing>());
  std::stable_sort(std::begin(s2), std::end(s2));
// end of LLM generated code

 assert(s == s2);
 assert(std::is_sorted(std::begin(s), std::end(s)));

 std::cout << "Test passed!" << std::endl;
 return 0;
}

