#include <parlay/worker_specific.h>
#include <parlay/primitives.h>
#include <iostream>
#include <thread>
#include <chrono>
#include <cassert>
#include <cmath>

int main() {
 struct WorkerStats {
   int count;
   double total_value;
   WorkerStats() : count(0), total_value(0.0) {}
 };

 parlay::WorkerSpecific<WorkerStats> stats_per_worker([]() { return WorkerStats(); });

 parlay::parallel_for(0, 1000, [&](size_t i) {
   (*stats_per_worker).count++;
   (*stats_per_worker).total_value += static_cast<double>(i);
   std::this_thread::sleep_for (std::chrono::milliseconds (1));
 }, 1);

 auto it = stats_per_worker.begin();

 int total_count = 0;
 double total_value_sum = 0.0;
 for (unsigned p = 0; p < parlay::num_workers(); p++) {
   const auto& stats = it[p];
   total_count += stats.count;
   total_value_sum += stats.total_value;
   assert(stats.count >= 0);
   assert(stats.total_value >= 0.0);
 }
 assert(total_count == 1000);
 assert(std::abs(total_value_sum - 499500.0) < 1e-9);

 std::cout << "Test passed!" << std::endl;
}

